const body = $json.body || $json;
const required = ['order_id','customer_name','customer_phone','items'];
const missing = required.filter(k => !body[k]);
if (missing.length) throw new Error('Missing fields: ' + missing.join(', '));
const items = Array.isArray(body.items) ? body.items : [];
let subtotal = 0;
const normalizedItems = items.map((item, index) => {
  const qty = Number(item.quantity || 1);
  const price = Number(item.unit_price || 0);
  const total = qty * price;
  subtotal += total;
  return { line_no:index+1, sku:item.sku||'', product_name:item.product_name||item.name||'Product', quantity:qty, unit_price:price, line_total:total };
});
const taxRate = Number(body.tax_rate || 0.18);
const tax = +(subtotal * taxRate).toFixed(2);
const shipping = Number(body.shipping || 0);
const discount = Number(body.discount || 0);
const grandTotal = +(subtotal + tax + shipping - discount).toFixed(2);
const invoiceNo = body.invoice_no || `INV-${new Date().getFullYear()}-${body.order_id}`;
return [{ json: { ...body, items: normalizedItems, invoice_no: invoiceNo, subtotal:+subtotal.toFixed(2), tax_rate:taxRate, tax, shipping, discount, grand_total:grandTotal, status:'INVOICE_GENERATED' } }];

const o = $json;
const rows = o.items.map(i => `<tr><td>${i.line_no}</td><td>${i.sku}</td><td>${i.product_name}</td><td>${i.quantity}</td><td>₹${i.unit_price}</td><td>₹${i.line_total}</td></tr>`).join('');
const html = `<!DOCTYPE html><html><head><meta charset="UTF-8"><style>
body{font-family:Arial;margin:30px;color:#111827}.invoice{max-width:800px;margin:auto;border:1px solid #e5e7eb;border-radius:18px;overflow:hidden}
.header{background:linear-gradient(135deg,#111827,#2563eb);color:white;padding:28px}.meta{display:flex;justify-content:space-between;padding:24px;background:#f8fafc}
.section{padding:24px}table{width:100%;border-collapse:collapse}th{background:#eff6ff;text-align:left;padding:12px}td{border-bottom:1px solid #e5e7eb;padding:12px}
.totals{margin-left:auto;width:320px}.totals div{display:flex;justify-content:space-between;padding:8px 0}.grand{font-size:22px;font-weight:bold;color:#2563eb;border-top:2px solid #dbeafe;margin-top:8px;padding-top:12px}
</style></head><body><div class="invoice"><div class="header"><h1>INVOICE</h1><p>Automated Order-to-Invoice Pipeline</p></div>
<div class="meta"><div><b>Bill To</b><br>${o.customer_name}<br>${o.customer_phone}<br>${o.customer_email||''}<br>${o.customer_address||''}</div>
<div><b>Invoice:</b> ${o.invoice_no}<br><b>Order:</b> ${o.order_id}<br><b>Date:</b> ${o.order_date||new Date().toISOString()}<br><b>Payment:</b> ${o.payment_method||'COD'}</div></div>
<div class="section"><table><thead><tr><th>#</th><th>SKU</th><th>Product</th><th>Qty</th><th>Unit</th><th>Total</th></tr></thead><tbody>${rows}</tbody></table></div>
<div class="section"><div class="totals"><div><span>Subtotal</span><b>₹${o.subtotal}</b></div><div><span>Tax</span><b>₹${o.tax}</b></div><div><span>Shipping</span><b>₹${o.shipping}</b></div><div><span>Discount</span><b>- ₹${o.discount}</b></div><div class="grand"><span>Total</span><span>₹${o.grand_total}</span></div></div></div>
</div></body></html>`;
return [{ json: { ...o, invoice_html: html } }];

const o = $items('Generate Invoice HTML')[0].json;
const msg = `Hi ${o.customer_name}, your order ${o.order_id} is confirmed. Invoice ${o.invoice_no} has been generated. Total: ₹${o.grand_total}. Thank you!`;
return [{ json: { ...o, whatsapp_message: msg } }];
